query:
-- Zambrero Karratha (C2791) services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services
WHERE customerExternalId IN ('C2791', 'C2565');

-- Zambrero Coomera Square (C0325) services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services
WHERE customerExternalId = 'C0325';

-- Zambrero Baldivis (C0300) services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services
WHERE customerExternalId = 'C0300';

-- TYS Molendinar (C2599 = The Yiros Shop MOLENDINAR) services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services
WHERE customerExternalId = 'C2599';

-- Zam Marrickville (C0295) services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services
WHERE customerExternalId = 'C0295';

-- Get remaining 18 billing items to see all
SELECT bi.id, bi.contactName, bi.description, bi.lineAmount FROM billing_items bi
WHERE (bi.serviceExternalId IS NULL OR bi.serviceExternalId = 'NULL')
ORDER BY bi.lineAmount DESC;

